const express = require('express');
const cors = require('cors');

const app = express();
app.use(cors());

app.use(express.json());

app.get("/products", (req,res) => {
        res.json([
            {
                id: 1,
                name: "Phone",
            }, 

            {
                id: 2,
                name: "Laptop",
            },

            {
                id: 3,
                name: "PC",
            },
        ]);
});


app.listen(3000, ()=> {
        console.log("Server is running...!");
});